// Extract customer data from webhook payload
// Webhook typeVersion 1.1 outputs body directly as $json
const payload = $input.first().json;
const customer = payload.customer || {};
const subscription = payload.subscription || {};

const customerEmail = customer.email || '';
const customerName = customer.name || '';
const customerPhone = customer.phone || '';
const planName = subscription.plan || '';
const amount = String(subscription.amount || '');

if (!customerEmail) {
    // Also try nested body (for backward compatibility with webhook v2)
    const bodyPayload = payload.body || {};
    const bodyCustomer = bodyPayload.customer || {};
    if (bodyCustomer.email) {
        return [{
            json: {
                customerEmail: bodyCustomer.email,
                customerName: bodyCustomer.name || '',
                customerPhone: bodyCustomer.phone || '',
                planName: (bodyPayload.subscription || {}).plan || '',
                amount: String((bodyPayload.subscription || {}).amount || '')
            }
        }];
    }
    throw new Error('Invalid payload: customer.email is required. Keys: ' + Object.keys(payload).join(','));
}

// Optional CS notification. Configure these env vars in your n8n instance.
const WAHA_NOTIFY_URL = $env.WAHA_NOTIFY_URL || '';
const WAHA_API_KEY = $env.WAHA_API_KEY || '';
const CS_NUMBER = $env.NOOVI_CS_NUMBER || '';

if (WAHA_NOTIFY_URL && WAHA_API_KEY && CS_NUMBER) {
    try {
        await this.helpers.request({
            method: 'POST',
            url: WAHA_NOTIFY_URL,
            headers: {
                'X-Api-Key': WAHA_API_KEY,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                chatId: CS_NUMBER + '@c.us',
                text: `🎉 *Novo cliente NooviChat!*\n\n👤 ${customerName || 'cliente'}\n📦 ${planName || 'plano confirmado'}\n🔗 Consulte os detalhes no portal autenticado.`,
                session: $env.WAHA_SESSION || 'default'
            })
        });
    } catch (e) {
        console.log('WAHA notification failed (non-critical):', e.message);
    }
} else {
    console.log('WAHA notification skipped: configure WAHA_NOTIFY_URL, WAHA_API_KEY and NOOVI_CS_NUMBER.');
}

// Optional CRM sync. Configure NOOVITRACK_CONTACTS_URL when available.
const NOOVITRACK_CONTACTS_URL = $env.NOOVITRACK_CONTACTS_URL || '';
if (NOOVITRACK_CONTACTS_URL) {
    try {
        await this.helpers.request({
            method: 'POST',
            url: NOOVITRACK_CONTACTS_URL,
            headers: {
                'Content-Type': 'application/json',
                'X-Source': 'noovihub-webhook'
            },
            body: JSON.stringify({
                name: customerName, email: customerEmail, phone: customerPhone,
                plan: planName, source: 'payment_webhook'
            })
        });
    } catch (e) {
        console.log('NooviTrack sync failed (non-critical):', e.message);
    }
} else {
    console.log('NooviTrack sync skipped: configure NOOVITRACK_CONTACTS_URL.');
}

return [{
    json: { customerEmail, customerName, customerPhone, planName, amount }
}];
